      "content": "const express = require('express');
const { sendError } = require('../../lib/errors');
const service = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;

  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'User ID and role are required');
  }

  const member = service.createMember(req.projectId, userId, role);

  if (member.error) {
    return sendError(res, member.status, member.error.code, member.error.message);
  }

  res.status(201).json({ member });
});

module.exports = router;
